const data = $input.first().json.body || $input.first().json;

const sessionId = data.sessionId || 'session-' + Date.now();
const message = (data.message || data.text || data.query || '').trim();
const customerEmail = data.customerEmail || data.email || '';
const customerName = data.customerName || data.name || 'there';

if (!message) {
  throw new Error('No message provided');
}

// Simple intent detection before hitting AI (saves API calls for obvious cases)
const msgLower = message.toLowerCase();

let detectedIntent = 'general';

const intents = {
  pricing: ['price', 'cost', 'how much', 'pricing', 'plan', 'fee', 'charge', 'preis', 'kosten'],
  hours: ['hours', 'open', 'close', 'schedule', 'when', 'öffnungszeiten'],
  refund: ['refund', 'return', 'money back', 'cancel', 'cancellation'],
  contact: ['phone', 'email', 'contact', 'reach', 'talk to', 'speak'],
  human: ['human', 'agent', 'person', 'real person', 'speak to someone', 'escalate']
};

for (const [intent, keywords] of Object.entries(intents)) {
  if (keywords.some(kw => msgLower.includes(kw))) {
    detectedIntent = intent;
    break;
  }
}

return [{
  json: {
    sessionId,
    message,
    customerEmail,
    customerName,
    detectedIntent,
    timestamp: new Date().toISOString()
  }
}];

// Package the escalation response
return [{
  json: {
    ...$input.first().json,
    aiResponse: null,
    escalated: true,
    reply: `Hi ${$input.first().json.customerName}, I understand you'd like to speak with a human agent. I'm connecting you now!\n\nIn the meantime, you can also reach us at:\n📧 [REPLACE_WITH_EMAIL]\n📞 [REPLACE_WITH_PHONE]\n⏰ [REPLACE_WITH_HOURS]\n\nA team member will be with you shortly.`
  }
}];

